var items = $input.all();

for (var i = 0; i < items.length; i++) {
  var item = items[i];
  var url = item.json.body.post.mediaItems[0].url;

  try {
    var helper = this.helpers;
    if (!helper && typeof $helpers !== "undefined") {
      helper = $helpers;
    }

    var res = await helper.httpRequest({
      url: url,
      method: "GET",
      resolveWithFullResponse: true,
      simple: false,
      followRedirect: true
    });

    var finalUrl = "";
    if (res.request && res.request.res && res.request.res.responseUrl) {
      finalUrl = res.request.res.responseUrl;
    } else if (res.request && res.request.responseURL) {
      finalUrl = res.request.responseURL;
    } else if (res.url) {
      finalUrl = res.url;
    } else if (res.request && res.request.href) {
      finalUrl = res.request.href;
    } else if (res.headers && res.headers.location) {
      finalUrl = res.headers.location;
    } else {
      finalUrl = url;
    }

    var shareId = finalUrl.split("share/")[1];
    if (shareId) {
      shareId = shareId.split("/")[0];
    } else {
      var reviewParts = finalUrl.split("review/");
      if (reviewParts.length > 1) {
        shareId = reviewParts[1].split("/")[0];
      } else {
        var urlParts = finalUrl.split("/");
        shareId = urlParts[urlParts.length - 1];
      }
    }

    var publicRes = await helper.httpRequest({
      url: "https://next.frame.io/api/share/" + shareId,
      method: "GET",
      json: true
    });

    var videoUrl = null;
    if (publicRes.shared_assets && publicRes.shared_assets.length > 0) {
      var media = publicRes.shared_assets[0].assets || [];
      var mp4 = media.find(function(m) { return m.ext === "mp4" || m.mime_type === "video/mp4"; });
      if (!mp4) {
        mp4 = publicRes.shared_assets[0];
      }
      videoUrl = mp4.url || mp4.master || mp4.h264_1080_download || publicRes.shared_assets[0].original_url;
    }
    item.json.finalMediaUrl = videoUrl; 
  } catch (e) {
    item.json.frameIoError = e.message;
    item.json.finalMediaUrl = item.json.body.post.mediaItems[0].dataUrl;
  }
}

return items;

const items = $input.all();
for (let item of items) {
  item.json.finalMediaUrl = item.json.body && item.json.body.post && item.json.body.post.mediaItems && item.json.body.post.mediaItems[0] ? item.json.body.post.mediaItems[0].dataUrl : '';
}
return items;

